import React from 'react'
import Boots from '../../assets/boots.png'
import './cart.css'

const Cart = () => {

    const carts = [
        {
            id: 1,
            image: Boots,
            title: "Nuriddin"
        }
    ]

    return (
        <div>
            {carts.map((cart) => {
                return (
                    <div className='cart' key={cart.id}>
                        <img src={cart.image} alt='boots' width='300'/>
                        <h1>{cart.title}</h1>
                    </div>
                )
            })}
        </div>
    )
} 

export default Cart
